local RunService = game:GetService("RunService") --[[ WindUI Example (wip) ]]\nlocal cloneref = (cloneref or clonereference or function(instance) return instance end)\nlocal ReplicatedStorage = cloneref(game:GetService("ReplicatedStorage"))\nlocal HttpService = cloneref(game:GetService("HttpService"))\nlocal WindUI do\n    local ok, result = pcall(function() return require("./src/Init") end)\n    if ok then\n        WindUI = result\n    else\n        if cloneref(game:GetService("RunService")):IsStudio() then\n            WindUI = require(cloneref(ReplicatedStorage:WaitForChild("WindUI"):WaitForChild("Init")))\n        else\n            WindUI = loadstring(game:HttpGet("https://raw.githubusercontent.com/Footagesus/WindUI/main/dist/main.lua"))()\n        end\n    end\nend\n\nfunction createPopup()\n    return WindUI:Popup({ Title = "Welcome to the WindUI!", Icon = "bird", Content = "Hello!", Buttons = { { Title = "Hahaha", Icon = "bird", Variant = "Tertiary", }, { Title = "Hahaha", Icon = "bird", Variant = "Tertiary", }, { Title = "Hahaha", Icon = "bird", Variant = "Tertiary", }, }, })\nend\n\nlocal Window = WindUI:CreateWindow({ Title = ".ftgs hub | WindUI Example", Folder = "ftgshub", Icon = "solar:folder-2-bold-duotone", NewElements = true, HideSearchBar = false, OpenButton = { Title = "Open .ftgs hub UI", CornerRadius = UDim.new(1, 0), StrokeThickness = 3, Enabled = true, Draggable = true, OnlyMobile = false, Scale = 0.5, Color = ColorSequence.new( Color3.fromHex("#30FF6A"), Color3.fromHex("#e7ff2f") ), }, Topbar = { Height = 44, ButtonsType = "Mac", }, })\ndo\n    Window:Tag({ Title = "v" .. WindUI.Version, Icon = "github", Color = Color3.fromHex("#1c1c1c"), Border = true, })\nend\n\nlocal Purple = Color3.fromHex("#7775F2")\nlocal Yellow = Color3.fromHex("#ECA201")\nlocal Green = Color3.fromHex("#10C550")\nlocal Grey = Color3.fromHex("#83889E")\nlocal Blue = Color3.fromHex("#257AF7")\nlocal Red = Color3.fromHex("#EF4F1D")\n